noncompliant:
struct Data { int value[100]; };
void init() {
  struct Data dest;
  memset(&dest, 0, sizeof(&dest));  // Noncompliant: sizeof pointer, not struct
}

compliant:
struct Data { int value[100]; };
void init() {
  struct Data dest;
  memset(&dest, 0, sizeof(dest));  // Compliant: sizeof the actual object
}

void copyArrays(int dest[20], int src[20], size_t count) {
  memcpy(dest, src, count * sizeof(int));  // Compliant: explicit size calculation
}
